mapper.insert:
insert into `pl_demand_plan_material_detail` (material_code, material_desc, material_unit,
logical_plant_no, logical_plant_name, plan_date,
amount, type, tenant_id
)
values

  (#{record.materialCode}, #{record.materialDesc}, #{record.materialUnit},
  #{record.logicalPlantNo}, #{record.logicalPlantName}, #{record.planDate},
  #{record.amount}, #{record.type}, #{record.tenantId}
  )

mapper.select:
select

from `pl_demand_plan_material_detail`
where is_delete != 1

  and material_code = #{materialCode}


  and logical_plant_no = #{logicalPlantNo}


  and tenant_id = #{tenantId}


  and plan_date = #{planDate}


  and amount = #{amount}


  and type = #{type}

select count(1)
from `pl_plan_material`
where is_delete = 0 and type = 2

  and tenant_id = #{tenantId}


  and logical_plant_no = #{logicalPlantNo}


  and material_code in

    #{code}

select material_code
from `pl_plan_material`
where is_delete=0 and type=2

  and tenant_id = #{tenantId}


  and logical_plant_no = #{logicalPlantNo}


  and material_code in

    #{code}



  limit #{start},#{pageSize}

(select material_code as material_code, material_desc as material_desc, material_unit as material_unit, logical_plant_no as logical_plant_no, logical_plant_name as logical_plant_name, plan_date as plan_date, amount as amount, type as type, '' as ext_info from `pl_demand_plan_material_detail` where is_delete = 0 and type in (1,3)
and tenant_id = #{tenantId}
and logical_plant_no = #{logicalPlantNo}
and material_code in
#{code}
and plan_date >= #{beginTime}
and plan_date <= #{endTime}
) UNION all (select detail.material_code as material_code, detail.material_desc as material_desc, detail.material_unit as material_unit, detail.logical_plant_no as logical_plant_no, detail.logical_plant_name as logical_plant_name, detail.plan_date as plan_date, detail.amount as amount, detail.type as type, period.ext_info as ext_info from ( select
from `pl_demand_plan_material_detail` where is_delete = 0 and type = 2 and tenant_id = #{tenantId} and plan_date >= #{beginTime} and plan_date <= #{endTime}
and material_code in
#{code}
) detail left join `pl_demand_plan_material_period` period on detail.material_code = period.material_code and detail.logical_plant_no = period.logical_plant_no and detail.plan_date = str_to_date(period.plan_period, '%Y/%m/%d %H:%i:%S') and detail.is_delete = period.is_delete where period.status = 1 and period.demand_type = 2 )

select pl_demand_plan_material_detail.* from ( select MAX(id) as id from `pl_demand_plan_material_detail` where is_delete = 0 and tenant_id = #{tenantId}
and logical_plant_no =#{logicalPlantNo}
and material_code in
#{code}
group by material_code ) a left join pl_demand_plan_material_detail on a.id = pl_demand_plan_material_detail.id

select distinct material_code, material_desc
from `pl_demand_plan_material_detail`
where is_delete != 1

  and tenant_id = #{tenantId}


  and logical_plant_no = #{logicalPlantNo}


  and material_desc like concat('%',#{materialDesc},'%')

insert.if:

  update `pl_demand_plan_material_detail`
  set amount = #{record.amount}, update_time = now()
  where id = #{record.id}
;
